import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
  X, Play, Pause, RotateCcw, BookOpen, 
  Volume2, VolumeX, Info, ChevronRight, 
  Settings, Languages, Sparkles, ScrollText, 
  History, Bookmark, ArrowDownCircle, Maximize2,
  Mic, MicOff, Layout, Share2, Search, Trophy
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { SAN_ZI_JING_DATA, SanZiJingVerse } from '../lib/sanzijingData';

const ThreeCharacterApp: React.FC<{ onClose: () => void }> = ({ onClose }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentVerseIdx, setCurrentVerseIdx] = useState(0);
  const [currentCharIdx, setCurrentCharIdx] = useState(-1);
  const [isVertical, setIsVertical] = useState(false);
  const [immersiveMode, setImmersiveMode] = useState(false);
  const [showPinyin, setShowPinyin] = useState(true);
  const [playbackRate, setPlaybackRate] = useState(0.85);
  const [activeDetail, setActiveDetail] = useState<SanZiJingVerse | null>(null);
  const [points, setPoints] = useState(() => Number(localStorage.getItem('szj_points') || 0));

  const scrollRef = useRef<HTMLDivElement>(null);
  const verseRefs = useRef<{ [key: number]: HTMLDivElement | null }>({});

  // 使用 Ref 追踪实时状态，避免 onend 闭包陷阱
  const isPlayingRef = useRef(false);
  const currentVerseIdxRef = useRef(0);

  // --- 语音播放引擎优化 ---
  const stopSpeech = useCallback(() => {
    window.speechSynthesis.cancel();
    isPlayingRef.current = false;
    setIsPlaying(false);
    setCurrentCharIdx(-1);
  }, []);

  const playVerse = useCallback((index: number) => {
    if (!('speechSynthesis' in window)) return;

    window.speechSynthesis.cancel();
    const verse = SAN_ZI_JING_DATA[index];
    const textToRead = verse.text;
    const utterance = new SpeechSynthesisUtterance(textToRead);

    utterance.lang = 'zh-CN';
    utterance.rate = playbackRate;
    utterance.pitch = 1.0;

    // 核心同步逻辑：监听边界事件
    utterance.onboundary = (event) => {
      if (!isPlayingRef.current) return;
      if (event.name === 'word' || event.name === 'char') {
        const textBefore = textToRead.substring(0, event.charIndex);
        const chineseOnlyBefore = textBefore.replace(/[^\u4e00-\u9fa5]/g, '');
        // 仅当索引变化时更新状态，减少无效渲染
        const newIdx = chineseOnlyBefore.length;
        setCurrentCharIdx(newIdx);
      }
    };

    utterance.onend = () => {
      // 检查是否应该继续播放下一段
      if (isPlayingRef.current) {
        if (index < SAN_ZI_JING_DATA.length - 1) {
          const next = index + 1;
          currentVerseIdxRef.current = next;
          setCurrentVerseIdx(next);
          // 延迟一点点开启下一段，给浏览器喘息时间
          setTimeout(() => {
            if (isPlayingRef.current) playVerse(next);
          }, 300);
        } else {
          stopSpeech();
          const newPoints = points + 50;
          setPoints(newPoints);
          localStorage.setItem('szj_points', String(newPoints));
        }
      }
    };

    utterance.onerror = () => stopSpeech();

    window.speechSynthesis.speak(utterance);

    // 自动滚动
    if (verseRefs.current[index]) {
      verseRefs.current[index]?.scrollIntoView({ behavior: 'smooth', block: 'center' });
    }
  }, [playbackRate, points, stopSpeech]);

  const handleTogglePlay = () => {
    if (isPlaying) {
      stopSpeech();
    } else {
      isPlayingRef.current = true;
      setIsPlaying(true);
      playVerse(currentVerseIdx);
    }
  };

  const handleVerseClick = (vIdx: number) => {
    // 如果正在播放，且点击的是当前段落，则视为切换播放/暂停
    if (isPlaying && currentVerseIdx === vIdx) {
      stopSpeech();
    } else {
      // 否则切换到点击的段落并开始朗读
      currentVerseIdxRef.current = vIdx;
      setCurrentVerseIdx(vIdx);
      isPlayingRef.current = true;
      setIsPlaying(true);
      playVerse(vIdx);
    }
  };

  const handleReset = () => {
    stopSpeech();
    currentVerseIdxRef.current = 0;
    setCurrentVerseIdx(0);
    scrollRef.current?.scrollTo({ top: 0, behavior: 'smooth' });
  };

  useEffect(() => {
    return () => { window.speechSynthesis.cancel(); };
  }, []);

  return (
    <div className={`fixed inset-0 z-50 bg-[#fdfbf7] flex flex-col font-serif text-[#2c3e50] overflow-hidden transition-all duration-700 ${immersiveMode ? 'bg-[#f8f5ee]' : ''}`}>
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none z-0 bg-[url('https://www.transparenttextures.com/patterns/rice-paper.png')]"></div>

      {/* 顶部 HUD */}
      {!immersiveMode && (
        <header className="h-16 md:h-20 bg-white/80 backdrop-blur-md border-b border-[#e0d7c6] flex items-center justify-between px-4 md:px-8 z-20 pt-[env(safe-area-inset-top)] shrink-0">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-[#c0392b] text-white rounded-xl flex items-center justify-center shadow-lg">
              <ScrollText size={24} />
            </div>
            <div>
              <h1 className="text-lg font-black tracking-tight">三字经 · 全文研习</h1>
              <div className="flex items-center gap-2 mt-0.5">
                <div className="h-1.5 w-32 bg-slate-100 rounded-full overflow-hidden">
                  <motion.div 
                    initial={{ width: 0 }}
                    animate={{ width: `${((currentVerseIdx + 1) / SAN_ZI_JING_DATA.length) * 100}%` }}
                    className="h-full bg-[#c0392b]" 
                  />
                </div>
                <span className="text-[9px] font-black text-[#c0392b] uppercase tracking-widest">进度: {Math.floor(((currentVerseIdx + 1) / SAN_ZI_JING_DATA.length) * 100)}%</span>
              </div>
            </div>
          </div>

          <div className="flex items-center gap-3">
            <button 
              onClick={() => setShowPinyin(!showPinyin)} 
              className={`p-2.5 rounded-full border transition-all ${showPinyin ? 'bg-[#c0392b] text-white border-[#c0392b]' : 'bg-white text-slate-400 border-slate-200'}`}
              title="显示/隐藏拼音"
            >
              <Languages size={18} />
            </button>
            <button onClick={() => setIsVertical(!isVertical)} className={`p-2.5 bg-[#f3efe6] rounded-full text-slate-500 hover:text-[#c0392b] transition-all ${isVertical ? 'rotate-90' : ''}`} title="切换竖排">
              <Layout size={18} />
            </button>
            <button onClick={() => setImmersiveMode(true)} className="p-2.5 bg-[#f3efe6] rounded-full text-slate-500 transition-all" title="沉浸模式">
              <Maximize2 size={18} />
            </button>
            <button onClick={onClose} className="p-2.5 bg-red-50 text-red-400 rounded-full hover:bg-red-500 hover:text-white transition-all"><X size={20}/></button>
          </div>
        </header>
      )}

      {/* 主体卷轴 */}
      <main 
        ref={scrollRef}
        className={`flex-1 overflow-y-auto no-scrollbar p-6 md:p-20 relative z-10 transition-all duration-1000 ${isVertical ? 'writing-vertical' : ''}`}
        style={{ writingMode: isVertical ? 'vertical-rl' : 'horizontal-tb' }}
      >
        <div className={`max-w-4xl mx-auto flex ${isVertical ? 'flex-row-reverse' : 'flex-col'} gap-10 md:gap-16 pb-32`}>
          {SAN_ZI_JING_DATA.map((verse, vIdx) => {
            const isVerseActive = currentVerseIdx === vIdx;
            return (
              <div 
                key={verse.id}
                ref={el => { verseRefs.current[vIdx] = el; }}
                onClick={() => handleVerseClick(vIdx)}
                className={`relative p-8 md:p-12 rounded-[2.5rem] md:rounded-[4rem] transition-all duration-700 cursor-pointer border-2 ${isVerseActive ? 'bg-white border-[#c0392b] shadow-[0_30px_70px_rgba(192,57,43,0.12)] scale-105' : 'border-transparent hover:border-[#e0d7c6] opacity-70 hover:opacity-100'}`}
              >
                <div className={`flex ${isVertical ? 'flex-col' : 'flex-row'} flex-wrap justify-center gap-6 md:gap-10 items-center`}>
                  {verse.chars.map((char, charIdx) => {
                    const isCharActive = isVerseActive && currentCharIdx === charIdx;
                    return (
                      <div key={charIdx} className="flex flex-col items-center">
                        {showPinyin && (
                          <span className={`text-[10px] md:text-sm font-mono mb-2 opacity-40 transition-all duration-300 ${isCharActive ? 'text-[#c0392b] opacity-100 translate-y-[-2px]' : ''}`}>
                            {verse.pinyin[charIdx]}
                          </span>
                        )}
                        <span 
                          className={`text-4xl md:text-7xl font-black transition-all duration-300 ${isCharActive ? 'text-[#c0392b] scale-110 drop-shadow-md' : (isVerseActive ? 'text-slate-600' : 'text-slate-300')}`}
                        >
                          {char}
                        </span>
                      </div>
                    );
                  })}
                </div>
                <div className={`absolute top-4 right-6 text-[8px] md:text-[10px] font-black uppercase tracking-[0.2em] text-[#c0392b]/20`}>Chapter_{verse.id.toString().padStart(2, '0')}</div>
              </div>
            );
          })}
        </div>
      </main>

      {/* 沉浸模式下的退出按钮 */}
      {immersiveMode && (
        <button 
          onClick={() => setImmersiveMode(false)}
          className="fixed top-8 right-8 z-[100] p-4 bg-white/20 backdrop-blur-md rounded-full text-slate-400 hover:text-[#c0392b] hover:bg-white transition-all shadow-xl"
        >
          <X size={24} />
        </button>
      )}

      {/* 底部控制栏 */}
      <footer className="bg-white/95 backdrop-blur-xl border-t border-[#e0d7c6] p-6 md:p-8 z-30 shadow-[0_-10px_30px_rgba(0,0,0,0.05)] shrink-0">
        <div className="max-w-4xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
          <div className="flex items-center gap-6">
             <button onClick={handleReset} className="p-3 text-slate-400 hover:text-[#c0392b] transition-colors"><RotateCcw size={24} /></button>
             <button 
                onClick={handleTogglePlay}
                className="w-16 h-16 md:w-20 md:h-20 bg-[#c0392b] text-white rounded-full flex items-center justify-center shadow-xl hover:scale-105 active:scale-95 transition-all"
             >
                {isPlaying ? <Pause size={32} fill="white" /> : <Play size={32} className="ml-1" fill="white" />}
             </button>
             <div className="flex flex-col">
                <span className="text-[9px] font-black text-slate-400 uppercase tracking-widest">语音语速</span>
                <select 
                  value={playbackRate} 
                  onChange={(e) => {
                    const rate = parseFloat(e.target.value);
                    setPlaybackRate(rate);
                    if(isPlaying) {
                        stopSpeech();
                        setTimeout(() => { 
                          isPlayingRef.current = true;
                          setIsPlaying(true); 
                          playVerse(currentVerseIdx); 
                        }, 200);
                    }
                  }}
                  className="bg-transparent text-sm font-bold text-[#c0392b] outline-none"
                >
                  <option value="0.7">缓读 0.7x</option>
                  <option value="0.85">常速 0.85x</option>
                  <option value="1.1">疾读 1.1x</option>
                </select>
             </div>
          </div>

          <div className="flex items-center gap-4">
             <button 
              onClick={() => setActiveDetail(SAN_ZI_JING_DATA[currentVerseIdx])}
              className="flex items-center gap-2 px-8 py-4 bg-[#2c3e50] text-white rounded-full font-black text-xs uppercase tracking-widest hover:bg-[#c0392b] transition-all shadow-lg active:scale-95"
             >
                <BookOpen size={14} /> 研读注释
             </button>
          </div>
        </div>
      </footer>

      {/* 译文侧边栏 */}
      <AnimatePresence>
        {activeDetail && (
          <motion.div 
            initial={{ x: '100%' }}
            animate={{ x: 0 }}
            exit={{ x: '100%' }}
            className="fixed inset-y-0 right-0 w-full md:w-[500px] bg-white z-[110] shadow-2xl flex flex-col border-l border-[#e0d7c6]"
          >
            <div className="p-8 md:p-12 flex-1 overflow-y-auto no-scrollbar">
              <div className="flex justify-between items-center mb-12">
                <div className="p-3 bg-[#c0392b]/10 rounded-2xl">
                  <ScrollText className="text-[#c0392b]" />
                </div>
                <button onClick={() => setActiveDetail(null)} className="p-2 bg-slate-50 rounded-full text-slate-400 hover:text-red-500 transition-colors"><X /></button>
              </div>

              <div className="mb-10">
                <h2 className="text-3xl font-black text-[#2c3e50] mb-4 tracking-widest leading-snug" style={{ fontFamily: 'serif' }}>{activeDetail.text}</h2>
                <div className="text-sm font-mono text-[#c0392b] font-bold tracking-[0.2em]">{activeDetail.pinyin.join(' ')}</div>
              </div>

              <div className="space-y-12">
                <section>
                  <h4 className="text-[10px] font-black uppercase text-[#c0392b] tracking-[0.3em] mb-4 italic">现代译文</h4>
                  <p className="text-lg text-slate-600 leading-relaxed font-medium italic">“{activeDetail.meaning}”</p>
                </section>

                <section className="bg-[#fdfbf7] p-8 rounded-[2.5rem] border border-[#e0d7c6] relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-4 opacity-[0.05]"><History size={80}/></div>
                  <div className="flex items-center gap-2 mb-4">
                    <Sparkles size={16} className="text-[#c0392b]" />
                    <h4 className="text-sm font-black text-[#2c3e50] uppercase tracking-widest">{activeDetail.allusion.title}</h4>
                  </div>
                  <p className="text-sm text-slate-500 leading-relaxed mb-6 italic">{activeDetail.allusion.content}</p>
                  <div className="text-[10px] text-slate-300 font-bold uppercase">— 出处: {activeDetail.allusion.source}</div>
                </section>
              </div>

              <button className="w-full mt-12 py-5 bg-[#c0392b] text-white rounded-2xl font-black text-xs uppercase tracking-widest flex items-center justify-center gap-3 active:scale-95 transition-transform shadow-xl">
                <Share2 size={16} /> 生成精美海报
              </button>
            </div>
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .writing-vertical {
          padding-top: 15vh;
          height: 100%;
        }
        .no-scrollbar::-webkit-scrollbar { display: none; }
      `}</style>
    </div>
  );
};

export default ThreeCharacterApp;

import React, { useState, useEffect } from 'react';
import { ShieldCheck, Zap, BookOpen, Trophy, Activity, Cpu } from 'lucide-react';
import { motion } from 'framer-motion';

const IntelDashboard: React.FC = () => {
  const [stats, setStats] = useState({
    chars: 0,
    poems: 0,
    points: 0,
    chess: 'NOVICE'
  });

  useEffect(() => {
    // 聚合各模块的数据
    const loadStats = () => {
      setStats({
        chars: Number(localStorage.getItem('char_learned') || 0),
        poems: Number(localStorage.getItem('poem_score') || 0),
        points: Number(localStorage.getItem('szj_points') || 0),
        chess: localStorage.getItem('chess_rank') || 'UNRANKED'
      });
    };
    loadStats();
    window.addEventListener('storage', loadStats);
    return () => window.removeEventListener('storage', loadStats);
  }, []);

  const dataCards = [
    { label: '神经元识字', value: stats.chars, unit: '单元', icon: BookOpen, color: 'text-emerald-400' },
    { label: '文化共鸣度', value: stats.poems, unit: '阶', icon: Zap, color: 'text-amber-400' },
    { label: '国学积分', value: stats.points, unit: 'EXP', icon: Trophy, color: 'text-rose-400' },
    { label: '逻辑算力', value: stats.chess, unit: '', icon: Activity, color: 'text-blue-400' },
  ];

  return (
    <div className="grid grid-cols-2 lg:grid-cols-4 gap-4 mb-12">
      {dataCards.map((card, idx) => (
        <motion.div 
          key={idx}
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: idx * 0.1 }}
          className="relative group cursor-default"
        >
          <div className="absolute -inset-[1px] bg-gradient-to-b from-white/10 to-transparent rounded-2xl -z-10 group-hover:from-emerald-500/20 transition-all duration-500"></div>
          <div className="bg-slate-900/40 backdrop-blur-xl border border-slate-800 p-4 md:p-6 rounded-2xl flex flex-col h-full overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-[0.03] group-hover:opacity-[0.07] transition-opacity">
              <card.icon size={64} />
            </div>

            <div className="flex items-center gap-2 mb-4">
              <div className={`p-2 bg-slate-800 rounded-lg ${card.color}`}>
                <card.icon size={16} />
              </div>
              <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest">{card.label}</span>
            </div>

            <div className="flex items-baseline gap-2">
              <span className="text-2xl md:text-3xl font-black text-white tech-font italic tracking-tighter">
                {typeof card.value === 'number' ? card.value.toLocaleString() : card.value}
              </span>
              <span className="text-[10px] font-bold text-slate-600 uppercase">{card.unit}</span>
            </div>

            <div className="mt-4 h-1 w-full bg-slate-800 rounded-full overflow-hidden">
              <motion.div 
                initial={{ width: 0 }}
                animate={{ width: '65%' }}
                className={`h-full ${card.color.replace('text-', 'bg-')}`}
              />
            </div>
          </div>
        </motion.div>
      ))}
    </div>
  );
};

export default IntelDashboard;

import React, { useState, useEffect } from 'react';
import { EDUCATION_ITEMS, ENTERTAINMENT_ITEMS, UTILITIES_ITEMS } from './constants';
import { AppItem } from './types';
import AppCard from './components/AppCard';
import Modal from './components/Modal';
import Earth3D from './components/Earth3D';
import FoodChainApp from './components/FoodChainApp';
import CharacterApp from './components/CharacterApp';
import ClockApp from './components/ClockApp';
import WaveApp from './components/WaveApp';
import MathSprintApp from './components/MathSprintApp';
import HistorySortingApp from './components/HistorySortingApp';
import BrainTeaseApp from './components/BrainTeaseApp';
import GobangApp from './components/GobangApp';
import ChineseChessApp from './components/ChineseChessApp';
import ChessApp from './components/ChessApp';
import ProArtApp from './components/ProArtApp';
import VocabularyApp from './components/VocabularyApp';
import IdiomApp from './components/IdiomApp';
import PoetryApp from './components/PoetryApp';
import ThreeCharacterApp from './components/ThreeCharacterApp';
import HeroSpotlight from './components/HeroSpotlight';
import ActivityTicker from './components/ActivityTicker';
import AuthUI from './components/AuthUI';
import IntelDashboard from './components/IntelDashboard';
import { Search, Cpu, Loader2, Terminal, LayoutGrid, Book, Gamepad2, Settings, Sparkles, Zap } from 'lucide-react';
import sql from './lib/neon';

const App: React.FC = () => {
  const [selectedItem, setSelectedItem] = useState<AppItem | null>(null);
  const [runningAppId, setRunningAppId] = useState<string | null>(null);
  const [isBooting, setIsBooting] = useState(false);
  const [bootingAppTitle, setBootingAppTitle] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [activeCategory, setActiveCategory] = useState<string>('ALL');

  const [allModules, setAllModules] = useState<AppItem[]>([]);
  const [user, setUser] = useState<{ email: string } | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  const staticModules = [...EDUCATION_ITEMS, ...ENTERTAINMENT_ITEMS, ...UTILITIES_ITEMS];

  useEffect(() => {
    const initIdentity = async () => {
      let identity = null;
      const saved = localStorage.getItem('zst_identity');

      if (saved) {
        identity = JSON.parse(saved);
      } else {
        const randomId = Math.random().toString(16).slice(2, 6).toUpperCase();
        identity = { email: `GUEST-${randomId}@zst.local` };
        localStorage.setItem('zst_identity', JSON.stringify(identity));
      }

      setUser(identity);

      if (sql && identity) {
        try {
          await sql`
            INSERT INTO portal_users (email) 
            VALUES (${identity.email}) 
            ON CONFLICT (email) DO NOTHING
          `;
        } catch (e) {
          console.warn("[Identity Sync] Offline or DB unavailable");
        }
      }
    };

    initIdentity();
    setAllModules(staticModules);
    setIsLoading(false);
  }, []);

  const filteredModules = allModules.filter(item => {
    const matchesSearch = item.title.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesCategory = activeCategory === 'ALL' || item.category.toUpperCase() === activeCategory;
    return matchesSearch && matchesCategory;
  });

  const handleRunApp = (item: AppItem) => {
    setSelectedItem(null); 
    setBootingAppTitle(item.title);
    setIsBooting(true);
    // 记录最近访问
    const recent = JSON.parse(localStorage.getItem('recent_apps') || '[]');
    const newRecent = [item.id, ...recent.filter((id: string) => id !== item.id)].slice(0, 4);
    localStorage.setItem('recent_apps', JSON.stringify(newRecent));

    setTimeout(() => {
      setIsBooting(false);
      setRunningAppId(item.id);
    }, 1200);
  };

  const categories = [
    { id: 'ALL', label: '核心链路', icon: LayoutGrid },
    { id: 'EDUCATION', label: '知识网', icon: Book },
    { id: 'ENTERTAINMENT', label: '虚拟区', icon: Gamepad2 },
    { id: 'UTILITIES', label: '工具链', icon: Settings },
  ];

  if (isBooting) {
    return (
      <div className="fixed inset-0 z-[100] bg-black flex flex-col items-center justify-center p-6">
        <div className="absolute inset-0 opacity-20 bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]"></div>
        <div className="relative">
          <div className="w-24 h-24 bg-emerald-500 clip-tech-border flex items-center justify-center animate-pulse shadow-[0_0_80px_rgba(16,185,129,0.4)]">
            <Cpu className="w-12 h-12 text-black animate-spin" />
          </div>
          <div className="absolute -inset-4 border-2 border-emerald-500/20 rounded-full animate-[ping_2s_infinite]"></div>
        </div>
        <h2 className="mt-12 text-center text-xl md:text-2xl font-black tech-font text-white italic tracking-widest uppercase">
          载入神经节点: {bootingAppTitle}
        </h2>
        <div className="mt-8 w-64 h-1 bg-slate-900 rounded-full overflow-hidden border border-white/5">
          <div className="h-full bg-emerald-500 animate-[loading_1.2s_linear_infinite] shadow-[0_0_15px_#10b981]"></div>
        </div>
        <p className="mt-4 font-mono text-[10px] text-emerald-500/50 animate-pulse tracking-widest uppercase">Encryption_Link_Established</p>
      </div>
    );
  }

  const renderApp = () => {
    switch (runningAppId) {
      case 'e1': return <Earth3D onClose={() => setRunningAppId(null)} />;
      case 'e2': return <FoodChainApp onClose={() => setRunningAppId(null)} />;
      case 'e3': return <WaveApp onClose={() => setRunningAppId(null)} />;
      case 'e4': return <CharacterApp onClose={() => setRunningAppId(null)} />;
      case 'e5': return <PoetryApp onClose={() => setRunningAppId(null)} />;
      case 'e6': return <HistorySortingApp onClose={() => setRunningAppId(null)} />;
      case 'e7': return <ClockApp onClose={() => setRunningAppId(null)} />;
      case 'e18': return <MathSprintApp onClose={() => setRunningAppId(null)} />;
      case 'e20': return <ThreeCharacterApp onClose={() => setRunningAppId(null)} />;
      case 'ent3': return <BrainTeaseApp onClose={() => setRunningAppId(null)} />;
      case 'ent4': return <GobangApp onClose={() => setRunningAppId(null)} />;
      case 'ent5': return <ChineseChessApp onClose={() => setRunningAppId(null)} />;
      case 'ent6': return <ChessApp onClose={() => setRunningAppId(null)} />;
      case 'u1': return <ProArtApp onClose={() => setRunningAppId(null)} />;
      case 'u2': return <VocabularyApp onClose={() => setRunningAppId(null)} userEmail={user?.email} />;
      case 'u3': return <IdiomApp onClose={() => setRunningAppId(null)} />;
      default: return (
        <div className="min-h-screen bg-black flex flex-col items-center justify-center text-center p-6">
          <Terminal className="w-12 h-12 text-emerald-500 mb-4 opacity-50" />
          <h1 className="text-xl font-bold text-white mb-2 tech-font uppercase">系统待机模式</h1>
          <p className="text-slate-500 mb-8 font-mono text-[10px] tracking-widest uppercase">ID: {runningAppId} / IN_DEV</p>
          <button onClick={() => setRunningAppId(null)} className="w-full max-w-xs py-4 border border-red-500/50 text-red-500 font-black tracking-[0.2em] uppercase italic clip-button hover:bg-red-500/10 transition-colors active:scale-95">终止进程</button>
        </div>
      );
    }
  };

  if (runningAppId) return renderApp();

  return (
    <div className="min-h-screen bg-[#020617] text-slate-300 pb-24 md:pb-20 relative overflow-x-hidden">
      {/* 全局背景增强 */}
      <div className="fixed inset-0 pointer-events-none z-0">
        <div className="absolute top-[-10%] left-[-10%] w-[40%] h-[40%] bg-emerald-500/5 blur-[120px] rounded-full"></div>
        <div className="absolute bottom-[-10%] right-[-10%] w-[40%] h-[40%] bg-blue-500/5 blur-[120px] rounded-full"></div>
      </div>

      <nav className="sticky top-0 z-40 bg-slate-950/60 backdrop-blur-xl border-b border-white/5 pt-[env(safe-area-inset-top)]">
        <div className="max-w-7xl mx-auto px-4 md:px-8 h-16 md:h-24 flex justify-between items-center">
          <div className="flex items-center gap-3 md:gap-5 cursor-pointer group" onClick={() => setActiveCategory('ALL')}>
            <div className="w-10 h-10 md:w-14 md:h-14 bg-emerald-500 flex items-center justify-center clip-button group-hover:shadow-[0_0_30px_rgba(16,185,129,0.5)] transition-all">
              <Cpu className="text-black w-6 h-6 md:w-8 md:h-8" />
            </div>
            <div className="flex flex-col">
              <span className="text-xl md:text-3xl font-black italic tech-font text-white tracking-tighter uppercase group-hover:text-emerald-400 transition-colors">知识通</span>
              <span className="text-[8px] md:text-[10px] font-mono text-emerald-500/50 tracking-widest uppercase hidden md:block">Neural_Learning_Portal_v2.0</span>
            </div>
          </div>

          <div className="flex items-center gap-4 md:gap-8">
            <div className="relative group hidden lg:block">
              <Search className="absolute left-5 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-500 group-focus-within:text-emerald-500 transition-colors" />
              <input 
                type="text" placeholder="检索系统模块..." value={searchQuery} onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-14 pr-8 py-3 bg-slate-900/50 border border-slate-800 text-xs font-mono focus:outline-none focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 w-48 transition-all focus:w-80 rounded-2xl backdrop-blur-md"
              />
            </div>
            <AuthUI user={user} />
          </div>
        </div>
      </nav>

      <main className="max-w-7xl mx-auto px-4 md:px-8 py-6 md:py-12 relative z-10">
        {!searchQuery && activeCategory === 'ALL' && allModules.length > 0 && (
          <>
            <HeroSpotlight item={allModules.find(m => m.id === 'e20') || allModules[0]} onRun={handleRunApp} />

            <div className="flex items-center gap-3 mb-6">
              <Zap className="text-amber-500 w-4 h-4 animate-pulse" />
              <h2 className="text-[10px] md:text-xs font-black text-slate-500 tech-font uppercase tracking-[0.4em]">智能情报中心 / INTEL_CENTER</h2>
            </div>
            <IntelDashboard />
          </>
        )}

        <div className="flex flex-col gap-8 mb-12 md:mb-16">
          <div className="flex items-center justify-between border-b border-slate-900 pb-6">
            <div className="flex items-center gap-4">
               <div className="p-2 bg-emerald-500/10 rounded-xl">
                 <LayoutGrid className="text-emerald-500 w-5 h-5 md:w-6 md:h-6" />
               </div>
               <h2 className="text-xl md:text-3xl font-black text-white tech-font uppercase tracking-tight italic">已部署模块</h2>
            </div>

            <div className="text-[10px] text-slate-500 font-mono hidden md:block">
              ACTIVE_NODES: <span className="text-emerald-500">{filteredModules.length}</span>
            </div>
          </div>

          <div className="flex bg-slate-900/30 p-2 rounded-[2rem] border border-white/5 backdrop-blur-md overflow-x-auto no-scrollbar touch-pan-x gap-2">
            {categories.map((cat) => {
              const Icon = cat.icon;
              const isActive = activeCategory === cat.id;
              return (
                <button
                  key={cat.id}
                  onClick={() => setActiveCategory(cat.id)}
                  className={`
                    flex items-center gap-3 px-6 md:px-10 py-3 md:py-4 rounded-2xl text-[11px] md:text-xs font-black tech-font uppercase tracking-widest transition-all duration-500 whitespace-nowrap active:scale-95
                    ${isActive 
                      ? 'bg-emerald-500 text-black shadow-[0_15px_30px_rgba(16,185,129,0.3)]' 
                      : 'text-slate-500 hover:text-slate-100 hover:bg-white/5'}
                  `}
                >
                  <Icon size={16} className={isActive ? 'text-black' : 'text-slate-500'} />
                  {cat.label}
                </button>
              );
            })}
          </div>
        </div>

        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8 md:gap-12">
          {filteredModules.length > 0 ? (
            filteredModules.map((item, idx) => (
              <AppCard key={item.id} item={item} onClick={setSelectedItem} />
            ))
          ) : (
            <div className="col-span-full py-32 flex flex-col items-center opacity-30">
              <Loader2 className="w-12 h-12 mb-6 animate-spin text-emerald-500" />
              <p className="tech-font text-xs uppercase tracking-[0.5em] text-center">无法探测到匹配子节点</p>
              <button onClick={() => {setSearchQuery(''); setActiveCategory('ALL');}} className="mt-8 px-8 py-3 border border-slate-800 rounded-full text-[10px] hover:bg-white/5 transition-all uppercase font-black">重置频率</button>
            </div>
          )}
        </div>
      </main>

      <ActivityTicker />

      {selectedItem && (
        <Modal 
          item={selectedItem} 
          onClose={() => setSelectedItem(null)} 
          onRun={handleRunApp} 
          user={user} 
        />
      )}

      <style>{`
        .tech-font { font-family: 'Orbitron', sans-serif; }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        @keyframes loading {
          0% { transform: translateX(-100%); }
          100% { transform: translateX(300%); }
        }
      `}</style>
    </div>
  );
};

export default App;

